var findMiddleIndex = function(nums) {
    const total = nums.reduce((a, b) => a + b, 0);
    let left = 0;
    for (let i = 0; i < nums.length; i++) {
        const right = total - left - nums[i];
        if (left === right) return i;
        left += nums[i];
    }
    return -1;
};
